using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD RESULT ===");
        Console.WriteLine($"Succeeded: {build.Succeeded}");
        Console.WriteLine();

        // Collect all errors and warnings
        var errors = new List<(string Project, string Code, string File, int Line, string Message)>();
        var warnings = new List<(string Project, string Code, string File, int Line, string Message)>();

        build.VisitAllChildren<Error>(e => {
            var project = GetProjectName(e);
            errors.Add((project, e.Code ?? "", e.File ?? "", e.LineNumber, e.Text ?? ""));
        });

        build.VisitAllChildren<Warning>(w => {
            var project = GetProjectName(w);
            warnings.Add((project, w.Code ?? "", w.File ?? "", w.LineNumber, w.Text ?? ""));
        });

        Console.WriteLine("=== ERRORS ===");
        foreach (var g in errors.GroupBy(e => e.Project))
        {
            Console.WriteLine($"\n--- Project: {g.Key} ---");
            foreach (var e in g)
            {
                Console.WriteLine($"  [{e.Code}] {e.File}({e.Line}): {e.Message}");
            }
        }

        Console.WriteLine("\n=== WARNINGS ===");
        foreach (var g in warnings.GroupBy(w => w.Project))
        {
            Console.WriteLine($"\n--- Project: {g.Key} ---");
            foreach (var w in g)
            {
                Console.WriteLine($"  [{w.Code}] {w.File}({w.Line}): {w.Message}");
            }
        }

        // Show project dependency order
        Console.WriteLine("\n=== PROJECT BUILD ORDER & DEPENDENCIES ===");
        build.VisitAllChildren<Project>(p => {
            Console.WriteLine($"\nProject: {p.Name} (Target: {p.TargetFramework})");
            Console.WriteLine($"  Succeeded: {p.Succeeded}");
        });
    }

    static string GetProjectName(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p)
                return p.Name;
            current = current.Parent;
        }
        return "<unknown>";
    }
}
