using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD RESULT ===");
        Console.WriteLine($"Succeeded: {build.Succeeded}");
        Console.WriteLine();

        // Collect all errors
        var errors = new List<(string Project, string Code, string File, int Line, string Message, string Subcategory)>();

        build.VisitAllChildren<Error>(e => {
            var project = GetProjectName(e);
            errors.Add((project, e.Code ?? "", e.File ?? "", e.LineNumber, e.Text ?? "", e.Subcategory ?? ""));
        });

        Console.WriteLine("=== ALL ERRORS (deduplicated) ===");
        var uniqueErrors = errors.Select(e => (e.Code, e.File, e.Line, e.Message)).Distinct().ToList();
        foreach (var e in uniqueErrors)
        {
            Console.WriteLine($"  [{e.Code}] {Path.GetFileName(e.File)}({e.Line}): {e.Message}");
        }

        // Check which projects had build errors
        Console.WriteLine("\n=== PROJECT STATUS ===");
        var projectStatus = new Dictionary<string, (bool hasErrors, bool hasCompileErrors)>();

        build.VisitAllChildren<Project>(p => {
            var key = p.Name;
            if (!projectStatus.ContainsKey(key))
                projectStatus[key] = (false, false);
        });

        foreach (var e in errors)
        {
            if (projectStatus.ContainsKey(e.Project))
            {
                var status = projectStatus[e.Project];
                status.hasErrors = true;
                if (e.Code.StartsWith("CS"))
                    status.hasCompileErrors = true;
                projectStatus[e.Project] = status;
            }
        }

        foreach (var kvp in projectStatus)
        {
            Console.WriteLine($"  {kvp.Key}: hasErrors={kvp.Value.hasErrors}, hasCompileErrors={kvp.Value.hasCompileErrors}");
        }

        // Check project references to identify dependency chain
        Console.WriteLine("\n=== PROJECT REFERENCES (from csproj content) ===");
        build.VisitAllChildren<Project>(p => {
            var refs = new List<string>();
            p.VisitAllChildren<Item>(item => {
                if (item.Name == "ProjectReference")
                    refs.Add(item.Text);
            });
            if (refs.Count > 0)
            {
                Console.WriteLine($"  {p.Name} references:");
                foreach (var r in refs.Distinct())
                    Console.WriteLine($"    -> {r}");
            }
        });

        // Check MSBuild error events for cascade detection
        Console.WriteLine("\n=== MSB ERROR CODES ===");
        var msbErrors = errors.Where(e => e.Code.StartsWith("MSB")).ToList();
        foreach (var e in msbErrors.Select(e => (e.Project, e.Code, e.Message)).Distinct())
        {
            Console.WriteLine($"  [{e.Code}] in {e.Project}: {e.Message}");
        }
    }

    static string GetProjectName(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p)
                return p.Name;
            current = current.Parent;
        }
        return "<unknown>";
    }
}
